const profile = $('Get Profile').first()?.json || {};
const content = $('Get Competitors').all().map(i => i.json).filter(i => i.title);
const approved = $('Get Approved').all().map(i => i.json).filter(i => i.title);
const rejected = $('Get Rejected').all().map(i => i.json).filter(i => i.title);
const existing = $('Get Existing').all().map(i => i.json).filter(i => i.title);
const webhook = $('Webhook').first().json;

let biz = '';
if(profile.brand_name) biz+='Marca: '+profile.brand_name+'\n';
if(profile.tagline) biz+='Tagline: '+profile.tagline+'\n';
if(profile.services) biz+='Servicios: '+profile.services+'\n';
if(profile.ideal_client) biz+='Cliente ideal: '+profile.ideal_client+'\n';
if(profile.differentiator) biz+='Diferenciador: '+profile.differentiator+'\n';
if(profile.tone_and_style) biz+='Tono: '+profile.tone_and_style+'\n';
if(profile.goals) biz+='Objetivos: '+profile.goals+'\n';
if(profile.avoid_topics) biz+='Evitar: '+profile.avoid_topics+'\n';

let fb='';
if(approved.length){fb+='APROBADAS:\n';approved.forEach(a=>fb+='OK: '+a.title+(a.feedback_notes?' — '+a.feedback_notes:'')+'\n');}
if(rejected.length){fb+='RECHAZADAS:\n';rejected.forEach(r=>fb+='NO: '+r.title+(r.feedback_notes?' — '+r.feedback_notes:'')+'\n');}

const comp = content.map(c=>c.title+': '+(c.analysis_notes||'').slice(0,200)).join('\n');
const exist = existing.map(e=>e.title).join(', ');

return [{json:{
  count: webhook.body?.count || 5,
  platform: webhook.body?.platform || 'multi',
  businessContext: biz,
  feedbackContext: fb,
  competitorContext: comp.slice(0,4000),
  existingTitles: exist.slice(0,2000)
}}];

const agentOutput = $input.first().json.output || $input.first().json.text || '';
const prev = $('Build Context').first().json;
return [{json:{...prev, researchBrief: agentOutput}}];

const output = $input.first().json.output || $input.first().json.text || '';
const platform = $('Prep Creativo').first().json.platform || 'multi';
const userId = $('Get Profile').first()?.json?.user_id || null;

let ideas = [];
try {
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) ideas = JSON.parse(jsonMatch[0]).ideas || [];
} catch(e) {}

const approved = ideas.filter(i => (i.verdict||'').toUpperCase().includes('APROBAR') || (i.score||0) >= 7);

if(approved.length === 0) return [{json:{_skip:true, _msg:'No approved ideas'}}];

return approved.map(idea => ({json:{
  title: idea.title || 'Sin titulo',
  description: idea.description || '',
  key_message: idea.key_message || '',
  content_type: idea.content_type || 'hot_take',
  source: 'agent',
  status: 'idea',
  priority: (idea.score||0) >= 8 ? 'high' : 'medium',
  platform: idea.platform || platform,
  user_id: userId
}}));

const saved = $('Save Ideas').all();
return [{json:{
  success: true,
  saved: saved.length,
  ideas: saved.map(i => ({title: i.json.title, id: i.json.id}))
}}];
